        const details = ALL_ITEM_DETAILS[item.id] as any;

        if (item.category === 'pills') {
            if (!isSelectingQty) {
                setIsSelectingQty(true);
            } else {
                const finalQty = Math.max(1, Math.min(useQty, member.personalInventory.pills[item.id] || 0));
                onUsePill(item.id, finalQty);
                setFocusedItem(null);
