                                            onClick={(e) => e.stopPropagation()}
                                        >
                                            {isRestricted ? (
                                                <p className="text-[10px] text-red-500 font-bold bg-black/60 px-2 py-1 rounded">境界不足</p>
                                            ) : (
                                                <>
                                                    {isSelectingQty && item.category === 'pills' ? (
                                                        <div className="flex flex-col items-center gap-2 w-full animate-fade-in">
                                                            <div className="flex items-center gap-1 bg-white/5 p-1 rounded border border-white/10 w-full justify-between">
                                                                <button 
                                                                    onClick={() => setUseQty(Math.max(1, useQty - 1))}
                                                                    className="w-7 h-7 flex items-center justify-center bg-black/40 text-gray-400 hover:text-white rounded border border-white/5 active:scale-90"
                                                                >-</button>
                                                                <input 
                                                                    type="number"
                                                                    value={useQty}
                                                                    onChange={(e) => setUseQty(Math.max(1, Math.min(item.count, parseInt(e.target.value) || 1)))}
