                                                            <div className="flex gap-2 w-full">
                                                                <button 
                                                                    onClick={() => handleAction(item)}
                                                                    className={`flex-1 py-1.5 rounded text-white text-[11px] font-bold ${style.bg.replace('40', '90')} border ${style.border} hover:brightness-125 shadow-md`}
