import React, { useState, useMemo, useEffect, useRef } from 'react';
import { ClanMember } from '../../../types';
import { ALL_ITEM_DETAILS } from '../../../constants';
import { getGradeStyle } from '../Shared/utils';

interface Props {
    member: ClanMember;
    onUsePill: (id: number, qty: number) => void;
    onEquip: (id: number, cat: 'weapon' | 'armor' | 'accessory' | 'treasure') => void;
    showTooltip: (e: React.MouseEvent, content: React.ReactNode) => void;
    hideTooltip: () => void;
    renderItemTooltip: (id: number) => React.ReactNode;
}

type BagSubTab = 'all' | 'equipment' | 'pills' | 'materials' | 'methods';
type SortKey = 'grade' | 'quantity' | 'name';

const BagTab: React.FC<Props> = ({ member, onUsePill, onEquip, showTooltip, hideTooltip, renderItemTooltip }) => {
    const [bagSubTab, setBagSubTab] = useState<BagSubTab>('all');
    const [bagSortKey, setBagSortKey] = useState<SortKey>('grade');
    const [focusedItem, setFocusedItem] = useState<number | null>(null);
    const [isSelectingQty, setIsSelectingQty] = useState<boolean>(false);
    const [useQty, setUseQty] = useState<number>(1);

    // Use a ref to the list container to handle background clicks
    const listRef = useRef<HTMLDivElement>(null);

    // Clicking anywhere outside the items/action panel will reset selection
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            // We want to reset focus if the click target is the scrollable list background itself
            if (event.target === listRef.current) {
                setFocusedItem(null);
                setIsSelectingQty(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    // Reset quantity selection when focus changes
    useEffect(() => {
        setUseQty(1);
        setIsSelectingQty(false);
    }, [focusedItem]);

    const sortedItems = useMemo(() => {
        const inv = member.personalInventory;
        const itemsList: Array<{ id: number; count: number; category: BagSubTab }> = [];
        const add = (rec: Record<number, number>, cat: BagSubTab) => Object.entries(rec).forEach(([id, count]) => count > 0 && itemsList.push({ id: parseInt(id), count, category: cat }));

        if (bagSubTab === 'all' || bagSubTab === 'equipment') add(inv.weapons, 'equipment');
        if (bagSubTab === 'all' || bagSubTab === 'pills') add(inv.pills, 'pills');
        if (bagSubTab === 'all' || bagSubTab === 'materials') { add(inv.herbs, 'materials'); add(inv.minerals, 'materials'); }
        if (bagSubTab === 'all' || bagSubTab === 'methods') add(inv.methods, 'methods');

        return itemsList.sort((a, b) => {
            const dA = ALL_ITEM_DETAILS[a.id];
            const dB = ALL_ITEM_DETAILS[b.id];
            if (!dA || !dB) return 0;
            if (bagSortKey === 'grade') return (typeof dB.grade === 'number' ? dB.grade : 0) - (typeof dA.grade === 'number' ? dA.grade : 0);
            return bagSortKey === 'quantity' ? b.count - a.count : dA.name.localeCompare(dB.name, 'zh-CN');
        });
    }, [member, bagSubTab, bagSortKey]);

    const handleAction = (item: { id: number, category: BagSubTab }) => {
        const details = ALL_ITEM_DETAILS[item.id] as any;

        if (item.category === 'pills') {
            if (!isSelectingQty) {
                // First click: show qty selector
                setIsSelectingQty(true);
            } else {
                // Second click (Confirm): actually use
                const finalQty = Math.max(1, Math.min(useQty, member.personalInventory.pills[item.id] || 0));
                onUsePill(item.id, finalQty);
                setFocusedItem(null);
            }
        } else if (item.category === 'equipment') {
            let cat: 'weapon' | 'armor' | 'accessory' | 'treasure' = 'weapon';
            if (details.name.includes('佩') || details.name.includes('戒') || details.name.includes('镯')) cat = 'accessory';
            else if (details.name.includes('甲') || details.name.includes('袍')) cat = 'armor';
            else if (details.name.includes('印') || details.name.includes('镜') || details.name.includes('壶')) cat = 'treasure';
            onEquip(item.id, cat);
            setFocusedItem(null);
        }
        hideTooltip();
    };

    return (
        <div className="h-full flex flex-col min-h-0 animate-fade-in pr-2 overflow-hidden">
