import { Realm, TalentTier, RootGrade, ClanMember } from '../../../types';
import { GENERATION_PAIRS } from '../../../data/metadata';

/**
 * 递归计算族人的代数
 */
export const calculateMemberGeneration = (member: ClanMember, allMembers: ClanMember[]): number => {
    if (!member.fatherId) return -1;
    const father = allMembers.find(m => m.id === member.fatherId);
    if (!father) return -1;
    return calculateMemberGeneration(father, allMembers) + 1;
};

/**
 * 获取辈分详细称号
 */
export const getGenerationTitle = (gen: number): string => {
    if (gen === -1) return "一世·老祖";
    if (gen === 0) return "二世·黎泾五子";

    const titles: Record<number, string> = {
        1: "三世·玄景",
        2: "四世·渊清",
        3: "五世·曦月",
        4: "六世·承明",
        5: "七世·周行",
        6: "八世·绛阙"
    };

    return titles[gen] || `${gen + 1}世子弟`;
};

export const getGenerationChar = (gen: number, gender: '男' | '女'): string => {
    const pair = GENERATION_PAIRS[gen];
    if (pair) return gender === '男' ? pair[0] : pair[1];
    return '';
};

/**
 * 获取物品品级对应的视觉样式
 * 0-2: 凡品 (灰色/白色)
 * 3: 灵品 (绿色)
 * 4-5: 珍品 (蓝色)
 * 6-7: 极品 (紫色)
 * 8+: 仙品/神器 (金色/橙色)
 */
export const getGradeStyle = (grade: number | string | undefined) => {
    const g = typeof grade === 'number' ? grade : (grade === '神器残片' ? 9 : 0);

    if (g <= 2) return { 
        border: 'border-gray-500/30', 
        text: 'text-gray-300', 
        bg: 'bg-gray-900/20', 
        hover: 'hover:border-gray-400', 
        glow: '', 
        shadow: '' 
    };
    if (g === 3) return { 
        border: 'border-emerald-500/40', 
        text: 'text-emerald-400', 
        bg: 'bg-emerald-900/10', 
        hover: 'hover:border-emerald-400', 
        glow: 'shadow-[0_0_10px_rgba(16,185,129,0.2)]', 
        shadow: 'drop-shadow-[0_0_3px_rgba(16,185,129,0.6)]' 
    };
    if (g <= 5) return { 
        border: 'border-blue-500/40', 
        text: 'text-blue-400', 
        bg: 'bg-blue-900/10', 
        hover: 'hover:border-blue-400', 
        glow: 'shadow-[0_0_12px_rgba(59,130,246,0.2)]', 
        shadow: 'drop-shadow-[0_0_4px_rgba(59,130,246,0.7)]' 
    };
    if (g <= 7) return { 
        border: 'border-purple-500/40', 
        text: 'text-purple-400', 
        bg: 'bg-purple-900/10', 
        hover: 'hover:border-purple-400', 
        glow: 'shadow-[0_0_15px_rgba(168,85,247,0.3)]', 
        shadow: 'drop-shadow-[0_0_5px_rgba(168,85,247,0.8)]' 
    };
    return { 
        border: 'border-amber-500/50', 
        text: 'text-amber-400', 
        bg: 'bg-amber-900/20', 
        hover: 'hover:border-amber-400', 
        glow: 'shadow-[0_0_20px_rgba(245,158,11,0.4)]', 
        shadow: 'drop-shadow-[0_0_6px_rgba(245,158,11,0.9)]' 
    };
};

export const getGradeColor = (grade: number | string | undefined) => {
    const style = getGradeStyle(grade);
    return `${style.text} ${style.shadow}`;
};

export const getTierColor = (tier: TalentTier) => {
    switch (tier) {
        case '凡人': return 'text-text-disabled';
        case '普通': return 'text-accent-jade';
        case '超凡': return 'text-blue-400';
        case '天才': return 'text-purple-400';
        case '绝世': return 'text-orange-400';
        case '绝世天骄': return 'text-orange-400 font-bold';
        default: return 'text-text-muted';
    }
};

export const getTitleColor = (tier: TalentTier) => {
    return getTierColor(tier);
};

export const getRootGradeColor = (grade: RootGrade) => {
    switch (grade) {
        case '凡人': return 'text-text-disabled';
        case '下品灵根': return 'text-accent-jade';
        case '中品灵根': return 'text-blue-400';
        case '上品灵根': return 'text-purple-400';
        case '极品灵根': return 'text-orange-400';
        default: return 'text-text-muted';
    }
};

export const getRealmStyle = (realm: Realm) => {
    return "border-border-soft bg-bg-panel text-text-muted";
};

export const getRealmText = (realm: Realm, subRealm: number) => {
    if (realm === Realm.Mortal) return '凡人';
    return `${realm}${subRealm}层`;
};

export const getElementColorClass = (key: string) => {
    switch (key) {
        case 'gold': return 'text-accent-gold border-accent-gold/20';
        case 'wood': return 'text-accent-jade border-accent-jade/20';
        case 'water': return 'text-blue-400 border-blue-400/20';
        case 'fire': return 'text-red-400/70 border-red-400/10';
        case 'earth': return 'text-yellow-700/70 border-yellow-700/10';
        default: return 'text-text-muted border-border-soft';
    }
};

export const getElementName = (key: string) => {
    switch (key) {
        case 'gold': return '金';
        case 'wood': return '木';
        case 'water': return '水';
        case 'fire': return '火';
        case 'earth': return '土';
        default: return key;
    }
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { ClanMember } from '../../../types';
import { ALL_ITEM_DETAILS } from '../../../constants';
import { getGradeStyle } from '../Shared/utils';

interface Props {
    member: ClanMember;
    onUsePill: (id: number, qty: number) => void;
    onEquip: (id: number, cat: 'weapon' | 'armor' | 'accessory' | 'treasure') => void;
    showTooltip: (e: React.MouseEvent, content: React.ReactNode) => void;
    hideTooltip: () => void;
    renderItemTooltip: (id: number) => React.ReactNode;
}

type BagSubTab = 'all' | 'equipment' | 'pills' | 'materials' | 'methods';
type SortKey = 'grade' | 'quantity' | 'name';

const BagTab: React.FC<Props> = ({ member, onUsePill, onEquip, showTooltip, hideTooltip, renderItemTooltip }) => {
    const [bagSubTab, setBagSubTab] = useState<BagSubTab>('all');
    const [bagSortKey, setBagSortKey] = useState<SortKey>('grade');
    const [focusedItem, setFocusedItem] = useState<number | null>(null);
    const [isSelectingQty, setIsSelectingQty] = useState<boolean>(false);
    const [useQty, setUseQty] = useState<number>(1);

    // Use a ref to the list container to handle background clicks
    const listRef = useRef<HTMLDivElement>(null);

    // Clicking anywhere outside the items/action panel will reset selection
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            // We want to reset focus if the click target is the scrollable list background itself
            if (event.target === listRef.current) {
                setFocusedItem(null);
                setIsSelectingQty(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    // Reset quantity selection when focus changes
    useEffect(() => {
        setUseQty(1);
        setIsSelectingQty(false);
    }, [focusedItem]);

    const sortedItems = useMemo(() => {
        const inv = member.personalInventory;
        const itemsList: Array<{ id: number; count: number; category: BagSubTab }> = [];
        const add = (rec: Record<number, number>, cat: BagSubTab) => Object.entries(rec).forEach(([id, count]) => count > 0 && itemsList.push({ id: parseInt(id), count, category: cat }));

        if (bagSubTab === 'all' || bagSubTab === 'equipment') add(inv.weapons, 'equipment');
        if (bagSubTab === 'all' || bagSubTab === 'pills') add(inv.pills, 'pills');
        if (bagSubTab === 'all' || bagSubTab === 'materials') { add(inv.herbs, 'materials'); add(inv.minerals, 'materials'); }
        if (bagSubTab === 'all' || bagSubTab === 'methods') add(inv.methods, 'methods');

        return itemsList.sort((a, b) => {
            const dA = ALL_ITEM_DETAILS[a.id];
            const dB = ALL_ITEM_DETAILS[b.id];
            if (!dA || !dB) return 0;
            if (bagSortKey === 'grade') return (typeof dB.grade === 'number' ? dB.grade : 0) - (typeof dA.grade === 'number' ? dA.grade : 0);
            return bagSortKey === 'quantity' ? b.count - a.count : dA.name.localeCompare(dB.name, 'zh-CN');
        });
    }, [member, bagSubTab, bagSortKey]);

    const handleAction = (item: { id: number, category: BagSubTab }) => {
        const details = ALL_ITEM_DETAILS[item.id] as any;

        if (item.category === 'pills') {
            if (!isSelectingQty) {
                // First click: show qty selector
                setIsSelectingQty(true);
            } else {
                // Second click (Confirm): actually use
                const finalQty = Math.max(1, Math.min(useQty, member.personalInventory.pills[item.id] || 0));
                onUsePill(item.id, finalQty);
                setFocusedItem(null);
            }
        } else if (item.category === 'equipment') {
            let cat: 'weapon' | 'armor' | 'accessory' | 'treasure' = 'weapon';
            if (details.name.includes('佩') || details.name.includes('戒') || details.name.includes('镯')) cat = 'accessory';
            else if (details.name.includes('甲') || details.name.includes('袍')) cat = 'armor';
            else if (details.name.includes('印') || details.name.includes('镜') || details.name.includes('壶')) cat = 'treasure';
            onEquip(item.id, cat);
            setFocusedItem(null);
        }
        hideTooltip();
    };

    return (
        <div className="h-full flex flex-col min-h-0 animate-fade-in pr-2 overflow-hidden">
            <div className="flex flex-wrap items-center justify-between gap-4 mb-4 shrink-0">
                <div className="flex gap-2 p-1 bg-black/40 rounded-xl border border-yellow-900/20">
                    {(['all', 'equipment', 'pills', 'materials', 'methods'] as BagSubTab[]).map(t => (
                        <button key={t} onClick={() => setBagSubTab(t)} className={`px-4 py-1.5 text-[10px] rounded-lg transition-all font-bold ${bagSubTab === t ? 'bg-yellow-700 text-white' : 'text-gray-500 hover:text-gray-300'}`}>
                            {t === 'all' ? '📦 全部' : t === 'equipment' ? '🏮 装备' : t === 'pills' ? '💊 丹药' : t === 'materials' ? '🎋 材料' : '📜 功法'}
                        </button>
                    ))}
                </div>
                <div className="flex items-center gap-2 bg-black/40 px-2 py-1 rounded-lg border border-white/5">
                    <span className="text-[10px] text-gray-500 font-bold uppercase tracking-widest border-r border-white/10 pr-2">排序</span>
                    <select value={bagSortKey} onChange={(e) => setBagSortKey(e.target.value as SortKey)} className="bg-transparent text-[10px] text-yellow-600 outline-none font-bold cursor-pointer">
                        <option value="grade">按品级</option>
                        <option value="quantity">按数量</option>
                        <option value="name">按名称</option>
                    </select>
                </div>
            </div>

            <div 
                ref={listRef}
                className="flex-1 overflow-y-auto custom-scrollbar pb-10"
            >
                {sortedItems.length > 0 ? (
                    <div className="grid grid-cols-2 sm:grid-cols-4 lg:grid-cols-5 gap-x-4 gap-y-8 items-start pointer-events-none">
                        {sortedItems.map(item => {
                            const details = ALL_ITEM_DETAILS[item.id] as any;
                            const style = getGradeStyle(details.grade);
                            const isRestricted = details.requiredRealm && member.realm !== details.requiredRealm;
                            const isFocused = focusedItem === item.id;

                            return (
                                <div key={item.id} className="flex flex-col gap-[5px] pointer-events-auto">
                                    <div 
                                        onClick={(e) => { e.stopPropagation(); setFocusedItem(isFocused ? null : item.id); }} 
                                        onMouseEnter={(e) => showTooltip(e, renderItemTooltip(item.id))} 
                                        onMouseLeave={hideTooltip} 
                                        className={`${style.bg} border-2 ${isFocused ? 'border-yellow-500 scale-[1.02]' : style.border} ${style.glow} p-3 rounded-lg flex flex-col items-center aspect-[4/5] justify-between shadow-lg relative group overflow-hidden transition-all duration-200 cursor-pointer ${isRestricted ? 'opacity-50 grayscale' : ''}`}
                                    >
                                        <div className={`text-3xl mt-2 group-hover:scale-110 transition-transform ${style.shadow}`}>
                                            {item.category === 'equipment' ? '⚔️' : item.category === 'pills' ? '💊' : item.category === 'materials' ? '💎' : '📜'}
                                        </div>
                                        <span className={`text-[11px] font-bold text-center truncate w-full mt-2 px-1 ${style.text} ${style.shadow}`}>{details.name}</span>
                                        <span className="text-[11px] font-bold text-yellow-600/80 font-mono">数量：{item.count}</span>
                                    </div>

                                    {isFocused && (
                                        <div 
                                            className="bg-black/95 border border-yellow-900/40 rounded-lg p-2 flex flex-col items-center gap-2 animate-fade-in z-20 shadow-xl"
                                            onClick={(e) => e.stopPropagation()}
                                        >
                                            {isRestricted ? (
                                                <p className="text-[10px] text-red-500 font-bold bg-black/60 px-2 py-1 rounded">境界不足</p>
                                            ) : (
                                                <>
                                                    {isSelectingQty && item.category === 'pills' ? (
                                                        <div className="flex flex-col items-center gap-2 w-full animate-fade-in">
                                                            <div className="flex items-center gap-1 bg-white/5 p-1 rounded border border-white/10 w-full justify-between">
                                                                <button 
                                                                    onClick={() => setUseQty(Math.max(1, useQty - 1))}
                                                                    className="w-7 h-7 flex items-center justify-center bg-black/40 text-gray-400 hover:text-white rounded border border-white/5 active:scale-90"
                                                                >-</button>
                                                                <input 
                                                                    type="number"
                                                                    value={useQty}
                                                                    onChange={(e) => setUseQty(Math.max(1, Math.min(item.count, parseInt(e.target.value) || 1)))}
                                                                    className="w-12 bg-transparent text-[12px] text-yellow-500 font-mono font-bold text-center outline-none border-b border-yellow-500/30"
                                                                />
                                                                <button 
                                                                    onClick={() => setUseQty(Math.min(item.count, useQty + 1))}
                                                                    className="w-7 h-7 flex items-center justify-center bg-black/40 text-gray-400 hover:text-white rounded border border-white/5 active:scale-90"
                                                                >+</button>
                                                            </div>
                                                            <div className="flex gap-2 w-full">
                                                                <button 
                                                                    onClick={() => handleAction(item)}
                                                                    className={`flex-1 py-1.5 rounded text-white text-[11px] font-bold ${style.bg.replace('40', '90')} border ${style.border} hover:brightness-125 shadow-md`}
                                                                >确认</button>
                                                                <button 
                                                                    onClick={() => setIsSelectingQty(false)}
                                                                    className="flex-1 py-1.5 rounded bg-gray-800 text-gray-400 text-[11px] font-bold border border-white/5 hover:text-white"
                                                                >取消</button>
                                                            </div>
                                                        </div>
                                                    ) : (
                                                        <button 
                                                            onClick={() => handleAction(item)} 
                                                            className={`text-white text-[12px] py-2 px-3 rounded font-bold w-full ${style.bg.replace('40', '90')} border ${style.border} active:scale-95 transition-all shadow-lg hover:brightness-125 animate-fade-in`}
                                                        >
                                                            {item.category === 'pills' ? '使用' : item.category === 'equipment' ? '佩戴' : '查看'}
                                                        </button>
                                                    )}
                                                </>
                                            )}
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                ) : (
                    <div className="w-full py-24 text-center text-gray-700 italic border-2 border-dashed border-white/5 rounded-xl flex flex-col items-center gap-4">
                        <span className="text-5xl opacity-10">🎒</span>
                        <span>行囊空空如也</span>
                    </div>
                )}
            </div>
        </div>
    );
};

