    const [warehouseSubTab, setWarehouseSubTab] = useState<WarehouseSubTab>('all');
    const [warehouseSortKey, setWarehouseSortKey] = useState<SortKey>('grade');

    const { tooltip, showTooltip, hideTooltip } = useTooltip();

    const sortedWarehouseItems = useMemo(() => {
        const inv = state.inventory;
        const allItems: Array<{ id: number; count: number; category: WarehouseSubTab; icon: string }> = [];

        const addToAll = (record: Record<number, number>, category: WarehouseSubTab, icon: string) => {
            Object.entries(record).forEach(([id, count]) => {
                if (count > 0) allItems.push({ id: parseInt(id), count, category, icon });
            });
        };

        addToAll(inv.scrolls, 'scrolls', '📖');
        addToAll(inv.methods, 'methods', '📜');
        addToAll(inv.herbs, 'materials', '🌿');
        addToAll(inv.minerals, 'materials', '💎');
        addToAll(inv.pills, 'pills', '💊');
        addToAll(inv.weapons, 'equipment', '⚔️');

        const filtered = warehouseSubTab === 'all' 
            ? allItems 
            : allItems.filter(item => item.category === warehouseSubTab);

        return filtered.sort((a, b) => {
            const detailA = (ALL_ITEM_DETAILS as any)[a.id];
            const detailB = (ALL_ITEM_DETAILS as any)[b.id];
            if (!detailA || !detailB) return 0;

            if (warehouseSortKey === 'grade') {
                const gA = typeof detailA.grade === 'number' ? detailA.grade : (detailA.grade === '神器残片' ? 9 : 0);
                const gB = typeof detailB.grade === 'number' ? detailB.grade : (detailB.grade === '神器残片' ? 9 : 0);
                return gB - gA;
            } else if (warehouseSortKey === 'quantity') {
                return b.count - a.count;
            } else {
                return detailA.name.localeCompare(detailB.name, 'zh-CN');
            }
        });
    }, [state.inventory, warehouseSubTab, warehouseSortKey]);

    const aliveMembers = useMemo(() => state.members.filter(m => m.status !== 'dead' && m.family === '望月李氏'), [state.members]);

    const alreadyAssignedIds = useMemo(() => {
        return state.buildings.map(b => b.assignedMemberId).filter(id => id !== null) as string[];
    }, [state.buildings]);

    const realmStats = useMemo(() => {
        const stats: Record<string, number> = {};
        let maxRealmIdx = 0;
        aliveMembers.forEach(m => {
            stats[m.realm] = (stats[m.realm] || 0) + 1;
            maxRealmIdx = Math.max(maxRealmIdx, REALM_ORDER.indexOf(m.realm));
        });
        return REALM_ORDER.slice(0, maxRealmIdx + 1).reverse();
    }, [aliveMembers]);

    const hasBuilding = (type: string) => state.buildings.some(b => b.type === type && b.isFinished);

    const getBuildingProgress = (b: Building) => {
        const total = BUILDING_TYPES[b.type].baseTurns;
        const current = total - b.turnsRemaining;
        return (current / total) * 100;
    };

    const renderBuildingList = (category: string) => {
        return (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                {Object.entries(BUILDING_TYPES)
                    .filter(([_, info]) => info.category === category)
                    .map(([type, info]) => {
                        const b = state.buildings.find(building => building.type === type);
                        const isBuilding = b && !b.isFinished;
                        const isFinished = b && b.isFinished;
                        const canAfford = state.spiritStones >= info.baseCost;

                        return (
                            <div key={type} className={`p-6 bg-black/40 border rounded shadow-lg transition-all flex flex-col justify-between ${isFinished ? 'border-yellow-900/40 opacity-60' : 'border-yellow-900/20'}`}>
                                <div>
                                    <div className="flex justify-between items-center mb-4">
                                        <span className="text-3xl">{info.icon}</span>
                                        <span className="text-[10px] bg-yellow-900/20 px-2 py-1 rounded text-yellow-600 font-bold uppercase tracking-widest">{info.category}</span>
                                    </div>
                                    <h4 className="text-lg font-bold text-yellow-500 mb-2">{info.name}</h4>
                                    <p className="text-xs text-gray-500 leading-relaxed mb-4">{info.desc}</p>
                                </div>
                                <div className="space-y-4 pt-4 border-t border-yellow-900/10">
                                    <div className="flex justify-between items-center text-sm">
                                        <span className="text-gray-500">营造费用</span>
                                        <span className={`font-mono font-bold ${canAfford ? 'text-yellow-400' : 'text-red-500'}`}>✨ {info.baseCost}</span>
                                    </div>

                                    {isBuilding ? (
                                        <div className="space-y-2">
                                            <div className="w-full bg-black/40 h-1.5 rounded-full overflow-hidden">
                                                <div className="bg-yellow-600 h-full transition-all" style={{ width: `${getBuildingProgress(b)}%` }}></div>
                                            </div>
                                            <p className="text-[10px] text-gray-500 text-center">正在营造... 还需 {b.turnsRemaining} 载</p>
                                        </div>
                                    ) : (
                                        <button 
                                            disabled={isFinished || !canAfford}
                                            onClick={() => onAddBuilding(type)}
                                            className={`w-full py-2 rounded font-bold text-xs tracking-widest transition-all ${isFinished ? 'bg-gray-800 text-gray-500 cursor-not-allowed' : (canAfford ? 'bg-yellow-800 text-yellow-100 hover:bg-yellow-700' : 'bg-red-900/20 text-red-500 border border-red-900/30 cursor-not-allowed')}`}
                                        >
                                            {isFinished ? '已经拥有' : (canAfford ? '开始营造' : '灵石不足')}
                                        </button>
                                    )}
                                </div>
                            </div>
                        );
                    })}
            </div>
        );
    };

    const alchemyRoom = state.buildings.find(b => b.type === 'AlchemyRoom');
    const assignedAlchemist = aliveMembers.find(m => m.id === alchemyRoom?.assignedMemberId);

    const renderItemSlot = (icon: string, id: number, count: number) => {
        const details: any = (ALL_ITEM_DETAILS as any)[id];
        if (!details) return null;

        const style = getGradeStyle(details.grade);

        return (
            <div 
                key={id} 
                onMouseEnter={(e) => showTooltip(e, renderItemContent(id))}
                onMouseLeave={hideTooltip}
                // Fix: Change dropShadow to shadow as per the return type of getGradeStyle in utils.ts
                className={`${style.bg} border-2 ${style.border} ${style.glow} ${style.shadow} p-3 rounded-lg flex flex-col items-center group ${style.hover} transition-all aspect-[4/5] justify-between shadow-lg relative overflow-hidden cursor-help`}
            >
                <div className={`text-3xl mt-2 group-hover:scale-110 transition-transform ${style.shadow}`}>
                    {icon}
                </div>

                <span className={`text-[12px] font-bold text-center truncate w-full mt-2 px-1 ${style.text}`}>
                    {details.name}
                </span>

                <div className="mt-auto">
                    <span className="text-[11px] font-bold text-yellow-600/80 mt-auto font-mono">数量：{count}</span>
                </div>

                <div className="absolute top-1 right-1">
                    <span className={`text-[7px] font-bold px-1 rounded-sm border ${style.border} ${style.text} bg-black/60`}>
                        {typeof details.grade === 'number' ? `${details.grade}品` : details.grade}
                    </span>
                </div>
            </div>
        );
    };

    const renderPositionsTab = () => {
        const positionConfigs: Record<string, { cost: number; desc: string; icon: string }> = {
            '执事': { cost: 50, desc: '处理家族日常琐碎，负责资源调配。', icon: '📝' },
            '长老': { cost: 200, desc: '家族中坚力量，参与核心决策。', icon: '🍵' },
        };

        return (
            <div className="space-y-10 animate-fade-in max-w-5xl mx-auto">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-10">
                    {POSITIONS.filter(p => p !== '弟子' && p !== '家主').map(posName => {
                        const isUnlocked = state.unlockedPositions.includes(posName);
                        const config = positionConfigs[posName];
                        const canUnlock = state.merit >= config.cost;

                        return (
                            <div key={posName} className={`p-6 bg-black/40 border rounded-xl flex flex-col justify-between transition-all ${isUnlocked ? 'border-yellow-900/30' : 'border-gray-800 opacity-80'}`}>
                                <div className="flex justify-between items-start mb-4">
                                    <div className="flex items-center gap-3">
                                        <span className="text-3xl">{config.icon}</span>
                                        <div>
                                            <h4 className="text-lg font-bold text-yellow-500">{posName}</h4>
                                            <p className="text-[10px] text-gray-500 uppercase tracking-widest">族中职司</p>
                                        </div>
                                    </div>
                                    {isUnlocked ? (
                                        <span className="text-[9px] px-2 py-0.5 rounded-full border border-green-900/40 text-green-500 font-bold">已解封</span>
                                    ) : (
                                        <span className="text-[9px] px-2 py-0.5 rounded-full border border-gray-700 text-gray-500 font-bold">待开启</span>
                                    )}
                                </div>
                                <p className="text-xs text-gray-400 mb-6 italic leading-relaxed">{config.desc}</p>
                                {!isUnlocked && (
                                    <button 
                                        onClick={() => onUnlockPosition?.(posName, config.cost)}
                                        disabled={!canUnlock}
                                        className={`w-full py-2.5 rounded font-bold text-[11px] tracking-[0.2em] transition-all border ${canUnlock ? 'bg-yellow-900/20 border-yellow-700 text-yellow-500 hover:bg-yellow-900/40' : 'bg-black/20 border-gray-800 text-gray-700 cursor-not-allowed'}`}
                                    >
                                        解封所需：💠 {config.cost} 功德
                                    </button>
                                )}
                            </div>
                        );
                    })}
                </div>

                <div className="bg-black/30 p-6 rounded-xl border border-yellow-900/10">
                    <h3 className="text-yellow-600 font-bold text-sm mb-6 border-l-4 border-yellow-600 pl-4 tracking-[0.3em]">成员册封</h3>
                    <div className="space-y-3">
                        {aliveMembers.map(member => (
                            <div key={member.id} className="flex items-center justify-between p-4 bg-black/40 border border-white/5 rounded-lg group hover:border-yellow-900/40 transition-all">
                                <div className="flex items-center gap-4">
                                    <div className="text-center min-w-[60px]">
                                        <p className="text-xs text-yellow-100 font-bold">{member.name}</p>
                                        <p className="text-[9px] text-gray-500 mt-0.5">{member.realm}</p>
                                    </div>
                                    <div className="h-8 w-px bg-white/5 mx-2"></div>
                                    <div className="flex flex-col">
                                        <p className="text-[10px] text-gray-500">当前职位</p>
                                        <p className="text-sm text-orange-400 font-bold">{member.position}</p>
                                    </div>
                                </div>
                                <div className="flex items-center gap-3">
                                    <select 
                                        value={member.position}
                                        onChange={(e) => onUpdateMember(member.id, { position: e.target.value })}
                                        className="bg-[#2c1810] border border-yellow-900/40 px-3 py-1.5 rounded text-yellow-500 text-xs font-bold outline-none cursor-pointer hover:border-yellow-600 transition-colors"
                                    >
                                        {state.unlockedPositions.map(pos => (
                                            <option key={pos} value={pos}>{pos}</option>
                                        ))}
                                    </select>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        );
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-md p-4 overflow-hidden select-none">
            <Tooltip state={tooltip} />

            <div className="relative w-full max-w-6xl h-[85vh] bg-[#1a1310] border-[8px] border-[#4a3728] rounded-sm shadow-2xl flex flex-col font-serif">
                <div className="h-16 bg-[#2c1810] border-b border-yellow-900/30 flex items-center px-6 shrink-0 gap-6">
                    <h2 className="text-2xl font-cursive text-yellow-600 pr-4 border-r border-yellow-900/20">望月大社</h2>
                    <div className="flex h-full overflow-x-auto scrollbar-hide">
                        {[
                            { id: 'status', name: '家族概况', icon: '📜', color: 'yellow' },
                            { id: 'warehouse', name: '家族仓库', icon: '🏯', color: 'amber' },
                            { id: 'buildings', name: '建筑营造', icon: '🏗️', color: 'yellow' },
                            { id: 'positions', name: '职位册封', icon: '👔', color: 'yellow' },
                        ].map(t => (
                            <button key={t.id} onClick={() => setActiveTab(t.id as any)} className={`whitespace-nowrap px-6 h-full text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === t.id ? `border-${t.color}-500 text-${t.color}-500 bg-${t.color}-900/10` : 'border-transparent text-gray-500 hover:text-gray-400'}`}>
                                <span className="text-lg opacity-70">{t.icon}</span> {t.name}
                            </button>
                        ))}
                        {hasBuilding('AlchemyRoom') && <button onClick={() => setActiveTab('alchemy')} className={`whitespace-nowrap px-6 h-full text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'alchemy' ? 'border-pink-500 text-pink-500 bg-pink-900/10' : 'border-transparent text-gray-500 hover:text-gray-400'}`}><span>⚗️</span> 炼丹</button>}
                        {hasBuilding('Smithy') && <button onClick={() => setActiveTab('smithing')} className={`whitespace-nowrap px-6 h-full text-sm font-bold border-b-2 transition-all flex items-center gap-2 ${activeTab === 'smithing' ? 'border-blue-500 text-blue-500 bg-blue-900/10' : 'border-transparent text-gray-500 hover:text-gray-400'}`}><span>🔨</span> 炼器</button>}
                    </div>
                    <button onClick={onClose} className="ml-auto w-10 h-10 flex items-center justify-center text-gray-500 hover:text-white text-3xl transition-colors font-bold">×</button>
                </div>

                <div className="flex-1 overflow-y-auto p-8 custom-scrollbar bg-[#140f0d]">
                    {activeTab === 'status' && (
                        <div className="space-y-12 animate-fade-in max-w-6xl mx-auto">
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                                <div className="p-6 bg-black/40 border border-yellow-900/20 rounded shadow-inner">
                                    <h3 className="text-yellow-700 text-[11px] font-bold uppercase mb-6 tracking-widest flex items-center gap-2"><span>✨</span> 核心资源</h3>
                                    <div className="space-y-4 text-sm">
                                        <div className="flex justify-between items-center"><span className="text-gray-500">家族灵石</span><span className="text-yellow-500 font-bold font-mono">✨ {state.spiritStones}</span></div>
                                        <div className="flex justify-between items-center"><span className="text-gray-500">族中功德</span><span className="text-blue-500 font-bold font-mono">💠 {state.merit}</span></div>
                                        <div className="flex justify-between items-center"><span className="text-gray-500">家族底蕴</span><span className="text-purple-500 font-bold font-mono">🧬 {state.heritagePool}</span></div>
                                    </div>
                                </div>
                                <div className="p-6 bg-black/40 border border-blue-900/20 rounded shadow-inner">
                                    <h3 className="text-blue-700 text-[11px] font-bold uppercase mb-6 tracking-widest flex items-center gap-2"><span>📈</span> 境界分布</h3>
                                    <div className="space-y-3 text-sm">
                                        {realmStats.map(r => (
                                            <div key={r} className="flex justify-between items-center"><span className="text-gray-500">{r}</span><span className="text-gray-300 font-bold">{aliveMembers.filter(m => m.realm === r).length} 位</span></div>
                                        ))}
                                    </div>
                                </div>
                                <div className="p-6 bg-black/40 border border-green-900/20 rounded shadow-inner">
                                    <h3 className="text-green-700 text-[11px] font-bold uppercase mb-6 tracking-widest flex items-center gap-2"><span>🌿</span> 物产统计</h3>
                                    <div className="space-y-4 text-sm">
                                        <div className="flex justify-between items-center"><span className="text-gray-500">灵草存量</span><span className="text-green-500 font-bold font-mono">{(Object.values(state.inventory.herbs) as number[]).reduce((a, b) => a + b, 0)}</span></div>
                                        <div className="flex justify-between items-center"><span className="text-gray-500">矿石储备</span><span className="text-gray-400 font-bold font-mono">{(Object.values(state.inventory.minerals) as number[]).reduce((a, b) => a + b, 0)}</span></div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}

                    {activeTab === 'warehouse' && (
                        <div className="flex flex-col animate-fade-in max-w-5xl mx-auto h-full min-h-0">
                            <div className="flex flex-wrap items-center justify-between gap-4 mb-6 shrink-0 border-b border-yellow-900/30 pb-4">
                                <div className="flex gap-1 overflow-x-auto scrollbar-hide">
                                    {[
                                        { id: 'all', name: '全部', icon: '🏠', activeBg: 'bg-yellow-900/30', activeText: 'text-yellow-500' },
                                        { id: 'scrolls', name: '卷轴', icon: '📖', activeBg: 'bg-amber-800/20', activeText: 'text-amber-500' },
                                        { id: 'materials', name: '材料', icon: '💎', activeBg: 'bg-emerald-900/20', activeText: 'text-emerald-500' },
                                        { id: 'pills', name: '丹药', icon: '💊', activeBg: 'bg-pink-900/20', activeText: 'text-pink-500' },
                                        { id: 'equipment', name: '装备', icon: '⚔️', activeBg: 'bg-blue-900/20', activeText: 'text-blue-500' },
                                        { id: 'methods', name: '功法', icon: '📜', activeBg: 'bg-amber-800/20', activeText: 'text-amber-600' },
                                    ].map(tab => (
                                        <button 
                                            key={tab.id}
                                            onClick={() => setWarehouseSubTab(tab.id as any)} 
                                            className={`px-4 py-2 rounded text-[13px] font-bold transition-all flex items-center gap-2 border whitespace-nowrap ${warehouseSubTab === tab.id ? `${tab.activeBg} ${tab.activeText} border-yellow-600/50 shadow-lg` : 'bg-black/10 text-gray-600 border-transparent hover:text-gray-400'}`}
                                        >
                                            <span className="text-base">{tab.icon}</span> {tab.name}
                                        </button>
                                    ))}
                                </div>

                                <div className="flex items-center gap-2 bg-black/40 px-3 py-1.5 rounded-lg border border-white/5 shadow-inner">
                                    <span className="text-[11px] text-gray-500 font-bold uppercase tracking-widest border-r border-white/10 pr-3">排序</span>
                                    <select 
                                        value={warehouseSortKey}
                                        onChange={(e) => setWarehouseSortKey(e.target.value as SortKey)}
                                        className="bg-transparent text-[12px] text-yellow-600 outline-none font-bold cursor-pointer hover:text-yellow-400 transition-colors"
                                    >
                                        <option value="grade">按品级</option>
                                        <option value="quantity">按数量</option>
                                        <option value="name">按名称</option>
                                    </select>
                                </div>
                            </div>

                            <div className="bg-black/30 rounded-lg p-6 border border-white/5 h-[480px] overflow-y-auto custom-scrollbar relative">
                                {sortedWarehouseItems.length > 0 ? (
                                    <div className="grid grid-cols-2 sm:grid-cols-4 md:grid-cols-5 lg:grid-cols-6 gap-4">
                                        {sortedWarehouseItems.map(item => renderItemSlot(item.icon, item.id, item.count))}
                                    </div>
                                ) : (
                                    <div className="h-full flex flex-col items-center justify-center text-gray-700 italic gap-4">
                                        <span className="text-5xl opacity-20">🏯</span>
                                        <p className="text-[13px]">家族仓库中尚无此类物资</p>
                                    </div>
                                )}
                            </div>
                        </div>
                    )}

                    {activeTab === 'buildings' && (
                        <div className="space-y-10 animate-fade-in max-w-5xl mx-auto">
                            <div><h3 className="text-yellow-700 text-sm font-bold mb-5 border-l-4 border-yellow-700 pl-4 tracking-widest">资源产出建筑</h3>{renderBuildingList('资源产出')}</div>
                            <div><h3 className="text-blue-700 text-sm font-bold mb-5 border-l-4 border-blue-700 pl-4 tracking-widest">家族功能建筑</h3>{renderBuildingList('家族功能')}</div>
                            <div><h3 className="text-emerald-700 text-sm font-bold mb-5 border-l-4 border-emerald-700 pl-4 tracking-widest">修行基础建筑</h3>{renderBuildingList('修行基础')}</div>
                        </div>
                    )}

                    {activeTab === 'positions' && renderPositionsTab()}

                    {activeTab === 'alchemy' && alchemyRoom && (
                        <div className="flex gap-8 h-full animate-fade-in max-w-5xl mx-auto">
                            <div className="w-80 p-6 bg-black/40 border border-pink-900/20 rounded shadow-xl flex flex-col">
                                <h3 className="text-pink-600 font-bold text-lg mb-6 flex items-center gap-2"><span>⚗️</span> 丹鼎堂</h3>
                                <div className="bg-[#1a1215] p-5 rounded border border-pink-900/30">
                                    <div className="flex justify-between items-center mb-6">
                                        <p className="text-gray-500 text-[11px] font-bold uppercase tracking-widest shrink-0 mr-4">当前堂主</p>
                                        <select className="bg-[#2c1810] border border-yellow-900/40 px-2 py-1 rounded text-yellow-500 outline-none text-[10px] font-bold min-w-[120px] shadow-sm hover:border-yellow-600 transition-colors" 
                                            onChange={(e) => onAssignBuilding(alchemyRoom!.id, e.target.value || null)} 
                                            value={alchemyRoom?.assignedMemberId || ''}>
                                            <option value="">- 轮空 -</option>
                                            {aliveMembers
                                                .filter(m => m.talents.百艺天赋.炼丹 > 0 && (!alreadyAssignedIds.includes(m.id) || m.id === alchemyRoom?.assignedMemberId))
                                                .sort((a, b) => b.proficiencies.炼丹 - a.proficiencies.炼丹)
                                                .map(m => (
                                                <option key={m.id} value={m.id}>
                                                    {m.name} ({m.realm}) · {getArtisanTitle('炼丹', m.proficiencies.炼丹)}
                                                </option>
                                            ))}
                                        </select>
                                    </div>
                                    {assignedAlchemist ? (
                                        <div className="animate-fade-in">
                                            <p className="text-yellow-500 font-black text-2xl tracking-tighter">{assignedAlchemist.name}</p>
                                            <p className="text-pink-600 text-[13px] mt-1 font-bold">{getArtisanTitle('炼丹', assignedAlchemist.proficiencies.炼丹)}</p>
                                        </div>
                                    ) : <p className="italic text-gray-700 py-10 text-center border border-dashed border-pink-900/20 rounded text-[13px]">暂未任命</p>}
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default ClanManagement;
